1	import { NextRequest } from "next/server";
2	import { jwtVerify } from "jose";
3	
4	export interface AuthUser {
5	  userId: string;
6	  role: "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
7	  deptId: string;
8	}
9	
10	export class AuthError extends Error {
11	  constructor(
12	    message: string,
13	    public statusCode: number = 401,
14	  ) {
15	    super(message);
16	    this.name = "AuthError";
17	  }
18	}
19	
20	const AUTH_SECRET =
21	  process.env.AUTH_SECRET ?? "it-asset-dev-secret-change-in-production";
22	const secretKey = new TextEncoder().encode(AUTH_SECRET);
23	
24	export async function verifyAuth(
25	  request: NextRequest,
26	): Promise<AuthUser> {
27	  const authHeader = request.headers.get("authorization");
28	
29	  if (!authHeader?.startsWith("Bearer ")) {
30	    throw new AuthError("Missing or invalid authorization header");
31	  }
32	
33	  const token = authHeader.slice(7);
34	
35	  try {
36	    const { payload } = await jwtVerify(token, secretKey);
37	    return {
38	      userId: payload.sub as string,
39	      role: payload.role as AuthUser["role"],
40	      deptId: payload.deptId as string,
41	    };
42	  } catch {
43	    throw new AuthError("Invalid or expired token");
44	  }
45	}
46	
47	export function requireOneOf(
48	  user: AuthUser,
49	  ...roles: AuthUser["role"][]
50	): void {
51	  if (!roles.includes(user.role)) {
52	    throw new AuthError("Insufficient permissions", 403);
53	  }
54	}
