1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	import { sanitizeAssetInstance } from "@/lib/dto";
5	
6	export async function GET(request: NextRequest) {
7	  try {
8	    const user = await verifyAuth(request);
9	
10	    const url = request.nextUrl;
11	    const page = Math.max(1, parseInt(url.searchParams.get("page") ?? "1", 10));
12	    const pageSize = Math.min(
13	      100,
14	      Math.max(1, parseInt(url.searchParams.get("pageSize") ?? "20", 10)),
15	    );
16	
17	    const where = { holderId: user.userId };
18	
19	    const [assets, total] = await Promise.all([
20	      prisma.assetInstance.findMany({
21	        where,
22	        orderBy: { updatedAt: "desc" },
23	        skip: (page - 1) * pageSize,
24	        take: pageSize,
25	        include: { model: true },
26	      }),
27	      prisma.assetInstance.count({ where }),
28	    ]);
29	
30	    const sanitized = assets.map((a) =>
31	      sanitizeAssetInstance(
32	        a as any,
33	        user.role as "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE",
34	      ),
35	    );
36	
37	    return Response.json({
38	      data: sanitized,
39	      pagination: {
40	        page,
41	        pageSize,
42	        total,
43	        totalPages: Math.ceil(total / pageSize),
44	      },
45	    });
46	  } catch (e) {
47	    if (e instanceof AuthError) {
48	      return Response.json({ error: e.message }, { status: e.statusCode });
49	    }
50	    return Response.json({ error: "Internal server error" }, { status: 500 });
51	  }
52	}
