1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
4	
5	export async function GET(request: NextRequest) {
6	  try {
7	    const user = await verifyAuth(request);
8	    requireOneOf(user, "MANAGER", "IT_ADMIN");
9	
10	    const url = request.nextUrl;
11	    const page = Math.max(1, parseInt(url.searchParams.get("page") ?? "1", 10));
12	    const pageSize = Math.min(
13	      100,
14	      Math.max(1, parseInt(url.searchParams.get("pageSize") ?? "20", 10)),
15	    );
16	
17	    let where: Record<string, unknown>;
18	
19	    if (user.role === "IT_ADMIN") {
20	      // IT_ADMIN sees all PENDING_IT tickets
21	      where = { status: "PENDING_IT" };
22	    } else {
23	      // MANAGER sees tickets from their department that need manager approval
24	      where = {
25	        status: { in: ["PENDING_MANAGER_1"] },
26	        applicant: { deptId: user.deptId },
27	      };
28	    }
29	
30	    const [tickets, total] = await Promise.all([
31	      prisma.ticket.findMany({
32	        where: where as any,
33	        orderBy: { createdAt: "desc" },
34	        skip: (page - 1) * pageSize,
35	        take: pageSize,
36	        include: {
37	          applicant: { select: { id: true, name: true, email: true, deptId: true } },
38	          targetAsset: { include: { model: true } },
39	          targetModel: true,
40	        },
41	      }),
42	      prisma.ticket.count({ where: where as any }),
43	    ]);
44	
45	    return Response.json({
46	      data: tickets,
47	      pagination: {
48	        page,
49	        pageSize,
50	        total,
51	        totalPages: Math.ceil(total / pageSize),
52	      },
53	    });
54	  } catch (e) {
55	    if (e instanceof AuthError) {
56	      return Response.json({ error: e.message }, { status: e.statusCode });
57	    }
58	    return Response.json({ error: "Internal server error" }, { status: 500 });
59	  }
60	}
