1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	
5	export async function GET(
6	  request: NextRequest,
7	  { params }: { params: Promise<{ id: string }> },
8	) {
9	  try {
10	    const user = await verifyAuth(request);
11	    const { id } = await params;
12	
13	    const ticket = await prisma.ticket.findUnique({
14	      where: { id },
15	      include: {
16	        applicant: { select: { id: true, name: true, email: true, role: true, deptId: true } },
17	        targetAsset: { include: { model: true } },
18	        targetModel: true,
19	        assignedBy: { select: { id: true, name: true } },
20	        processor: { select: { id: true, name: true } },
21	        fromHolder: { select: { id: true, name: true } },
22	        toHolder: { select: { id: true, name: true } },
23	        targetDept: true,
24	        deputyApprover: { select: { id: true, name: true } },
25	        notifications: { orderBy: { createdAt: "desc" }, take: 10 },
26	      },
27	    });
28	
29	    if (!ticket) {
30	      return Response.json({ error: "Ticket not found" }, { status: 404 });
31	    }
32	
33	    const isApplicant = ticket.applicantId === user.userId;
34	    const isItAdmin = user.role === "IT_ADMIN";
35	
36	    // MANAGER can see tickets from their department
37	    const isManager = user.role === "MANAGER";
38	    let canView = isApplicant || isItAdmin;
39	
40	    if (isManager && !canView) {
41	      const dept = await prisma.department.findUnique({
42	        where: { id: user.deptId },
43	      });
44	      if (dept && dept.managerId === user.userId) {
45	        const applicant = await prisma.user.findUnique({
46	          where: { id: ticket.applicantId },
47	          select: { deptId: true },
48	        });
49	        if (applicant && applicant.deptId === user.deptId) {
50	          canView = true;
51	        }
52	      }
53	    }
54	
55	    if (!canView) {
56	      return Response.json({ error: "Forbidden" }, { status: 403 });
57	    }
58	
59	    return Response.json(ticket);
60	  } catch (e) {
61	    if (e instanceof AuthError) {
62	      return Response.json({ error: e.message }, { status: e.statusCode });
63	    }
64	    return Response.json({ error: "Internal server error" }, { status: 500 });
65	  }
66	}
