1	import { NextRequest } from "next/server";
2	import { verifyAuth, AuthError } from "@/lib/auth";
3	import { prisma } from "@/lib/prisma";
4	import { callDeepSeek } from "@/lib/ai/client";
5	import { withAiFallback } from "@/lib/ai/with-fallback";
6	import { generateConfirmationToken } from "@/lib/ai/confirmation-token";
7	
8	export async function POST(request: NextRequest) {
9	  try {
10	    const user = await verifyAuth(request);
11	
12	    const { message, history } = (await request.json()) as {
13	      message?: string;
14	      history?: { role: "user" | "assistant"; content: string }[];
15	    };
16	    if (!message || typeof message !== "string") {
17	      return Response.json(
18	        { error: "message is required" },
19	        { status: 400 },
20	      );
21	    }
22	
23	    const [assets, pendingTickets] = await Promise.all([
24	      prisma.assetInstance.findMany({
25	        where: { holderId: user.userId },
26	        include: { model: true },
27	      }),
28	      prisma.ticket.findMany({
29	        where: {
30	          applicantId: user.userId,
31	          status: {
32	            in: [
33	              "SUBMITTED",
34	              "PENDING_MANAGER_1",
35	              "PENDING_MANAGER_2",
36	              "PENDING_IT",
37	              "IN_PROGRESS",
38	            ],
39	          },
40	        },
41	      }),
42	    ]);
43	
44	    const userContext = {
45	      assets: assets.map((a) => ({
46	        id: a.id,
47	        modelName: a.model.modelName,
48	        brandName: a.model.brandName,
49	        category: a.model.category,
50	        status: a.status,
51	        warrantyExpiry: a.warrantyExpiry.toISOString(),
52	      })),
53	      pendingTickets: pendingTickets.map((t) => ({
54	        id: t.id,
55	        type: t.type,
56	        status: t.status,
57	        createdAt: t.createdAt.toISOString(),
58	      })),
59	    };
60	
61	    const systemPrompt = `你是一个IT助手，帮助用户处理IT资产管理相关事务。
62	
63	## 原则
64	- 使用简洁友好的中文回复
65	- 涉及创建工单或申领设备时，需要先获得用户确认
66	- 用户询问价格或供应商信息时，回复"抱歉，该信息不在你的权限范围内"
67	- 根据用户上下文信息提供个性化帮助
68	
69	## 输入格式
70	{
71	  "history": [{"role": "user|assistant", "content": "..."}],
72	  "message": "用户当前消息",
73	  "userContext": {
74	    "assets": [{"id": "...", "modelName": "...", "brandName": "...", "category": "...", "status": "...", "warrantyExpiry": "..."}],
75	    "pendingTickets": [{"id": "...", "type": "...", "status": "...", "createdAt": "..."}]
76	  }
77	}
78	
79	## 意图分类
80	- query_asset: 查询资产信息
81	- query_warranty: 查询保修信息
82	- query_ticket: 查询工单状态
83	- guide_repair: 指导报修(需要用户确认)
84	- guide_apply: 指导申领(需要用户确认)
85	- fallback: 其他问题
86	
87	## 输出格式
88	{
89	  "intent": "query_asset|query_warranty|query_ticket|guide_repair|guide_apply|fallback",
90	  "reply": "回复内容",
91	  "needConfirmation": true/false,
92	  "pendingAction": {
93	    "type": "create_repair|create_apply",
94	    "description": "操作描述",
95	    "params": { ... }
96	  }
97	}`;
98	
99	    const historyMessages = (history ?? []).map((h) => ({
100	      role: h.role as "user" | "assistant",
101	      content: h.content,
102	    }));
103	
104	    const aiResult = await withAiFallback(
105	      () =>
106	        callDeepSeek<{
107	          intent: string;
108	          reply: string;
109	          needConfirmation: boolean;
110	          pendingAction: {
111	            type: "create_repair" | "create_apply";
112	            description: string;
113	            params: Record<string, unknown>;
114	          } | null;
115	        }>({
116	          messages: [
117	            { role: "system", content: systemPrompt },
118	            ...historyMessages,
119	            {
120	              role: "user",
121	              content: JSON.stringify({
122	                history: historyMessages,
123	                message,
124	                userContext,
125	              }),
126	            },
127	          ],
128	        }),
129	      "AI 助手暂时不可用，你可以通过「我的资产」查看资产信息，或通过「申领设备」/「报修」提交申请。",
130	    );
131	
132	    if (!aiResult.ok) {
133	      return Response.json(aiResult);
134	    }
135	
136	    // 如果 needConfirmation=true，生成 confirmationToken
137	    if (aiResult.data.needConfirmation && aiResult.data.pendingAction) {
138	      const token = await generateConfirmationToken({
139	        userId: user.userId,
140	        action: aiResult.data.pendingAction.type,
141	        params: aiResult.data.pendingAction.params,
142	      });
143	
144	      return Response.json({
145	        ok: true,
146	        data: {
147	          ...aiResult.data,
148	          confirmationToken: token,
149	        },
150	      });
151	    }
152	
153	    return Response.json(aiResult);
154	  } catch (e) {
155	    if (e instanceof AuthError) {
156	      return Response.json({ error: e.message }, { status: e.statusCode });
157	    }
158	    return Response.json({ error: "Internal server error" }, { status: 500 });
159	  }
160	}
