1	import { NextResponse } from "next/server";
2	import { SignJWT } from "jose";
3	import bcrypt from "bcryptjs";
4	import { prisma } from "@/lib/prisma";
5	
6	const AUTH_SECRET =
7	  process.env.AUTH_SECRET ?? "it-asset-dev-secret-change-in-production";
8	const secretKey = new TextEncoder().encode(AUTH_SECRET);
9	
10	export async function POST(request: Request) {
11	  try {
12	    const { email, password } = await request.json();
13	
14	    if (!email || !password) {
15	      return NextResponse.json(
16	        { error: "Email and password are required" },
17	        { status: 400 },
18	      );
19	    }
20	
21	    const user = await prisma.user.findUnique({ where: { email } });
22	
23	    if (!user) {
24	      return NextResponse.json(
25	        { error: "Invalid credentials" },
26	        { status: 401 },
27	      );
28	    }
29	
30	    if (user.status !== "ACTIVE") {
31	      return NextResponse.json(
32	        { error: "Account is not active" },
33	        { status: 401 },
34	      );
35	    }
36	
37	    const passwordValid = await bcrypt.compare(password, user.passwordHash);
38	
39	    if (!passwordValid) {
40	      return NextResponse.json(
41	        { error: "Invalid credentials" },
42	        { status: 401 },
43	      );
44	    }
45	
46	    const token = await new SignJWT({
47	      sub: user.id,
48	      email: user.email,
49	      name: user.name,
50	      role: user.role,
51	      deptId: user.deptId,
52	    })
53	      .setProtectedHeader({ alg: "HS256" })
54	      .setExpirationTime("24h")
55	      .sign(secretKey);
56	
57	    return NextResponse.json({
58	      user: {
59	        id: user.id,
60	        email: user.email,
61	        name: user.name,
62	        role: user.role,
63	        deptId: user.deptId,
64	      },
65	      token,
66	    });
67	  } catch (error) {
68	    return NextResponse.json(
69	      { error: "Internal server error" },
70	      { status: 500 },
71	    );
72	  }
73	}
