10	    requireOneOf(user, "EMPLOYEE", "MANAGER");
11	
12	    const { requirement } = (await request.json()) as {
13	      requirement?: string;
14	    };
15	    if (!requirement || typeof requirement !== "string") {
16	      return Response.json(
17	        { error: "requirement is required" },
18	        { status: 400 },
19	      );
20	    }
21	
22	    const models = await prisma.assetModel.findMany({
23	      where: { status: "ACTIVE" },
24	      include: {
25	        _count: {
26	          select: {
27	            instances: {
28	              where: { status: "IN_STOCK" },
29	            },
30	          },
31	        },
32	      },
33	    });
34	
35	    const modelListJson = JSON.stringify(
36	      models.map((m) => ({
37	        id: m.id,
38	        category: m.category,
39	        brandName: m.brandName,
40	        modelName: m.modelName,
41	        specs: m.specs,
42	        stock: m._count.instances,
43	        warrantyMonths: m.warrantyMonths,
44	      })),
45	    );
46	
47	    const systemPrompt = `你是一个专业的IT设备推荐助手。
48	用户会提供需求描述和可用型号列表。
49	你需要根据用户需求推荐最合适的设备型号。
50	
51	输出JSON格式:
52	{
53	  "recommendations": [
54	    { "modelId": "型号ID", "score": 分数(0-100), "reason": "推荐理由" }
55	  ],
56	  "topPick": "最佳型号ID"
57	}
58	
59	注意事项:
60	- 忽略已停产(DISCONTINUED)的型号
61	- 库存为0的型号标注"暂无库存"
62	- 评分范围0-100
63	- 按推荐度从高到低排序`;
64	
65	    const userMessage = `用户需求: ${requirement}\n\n可用型号: ${modelListJson}`;
66	
67	    const result = await withAiFallback(
68	      () =>
69	        callDeepSeek<{
70	          recommendations: {
71	            modelId: string;
72	            score: number;
73	            reason: string;
74	          }[];
75	          topPick: string;
76	        }>({
