2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
4	import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
5	import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
6	import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";
7	import { notifyApprovalResult } from "@/lib/notifications";
8	
9	export async function POST(
10	  request: NextRequest,
11	  { params }: { params: Promise<{ id: string }> },
12	) {
13	  try {
14	    const user = await verifyAuth(request);
15	    requireOneOf(user, "MANAGER", "IT_ADMIN");
16	
17	    const { id } = await params;
18	    const body = await request.json();
19	    const { rejectReason } = body;
20	
21	    if (!rejectReason) {
22	      return Response.json({ error: "rejectReason is required" }, { status: 400 });
23	    }
24	
25	    const result = await prisma.$transaction(async (tx) => {
26	      const ticket = await tx.ticket.findUnique({
27	        where: { id },
28	        include: { applicant: true, targetAsset: true },
29	      });
30	      if (!ticket) {
31	        throw new WorkflowError("Ticket not found");
32	      }
33	
34	      const currentStatus = ticket.status as import("@prisma/client").TicketStatus;
35	
36	      // Same role checks as approve
37	      if (currentStatus === "PENDING_MANAGER_1" || currentStatus === "PENDING_MANAGER_2") {
38	        if (user.role === "MANAGER") {
39	          const applicant = await tx.user.findUnique({
40	            where: { id: ticket.applicantId },
41	          });
42	          if (!applicant || applicant.deptId !== user.deptId) {
43	            throw new WorkflowError("You can only reject tickets for your own department");
44	          }
45	        }
46	      } else if (currentStatus === "PENDING_IT") {
47	        if (user.role !== "IT_ADMIN") {
48	          throw new WorkflowError("Only IT_ADMIN can reject at this stage");
49	        }
50	      } else if (currentStatus !== "APPROVED") {
51	        throw new WorkflowError(`Ticket cannot be rejected in ${currentStatus} status`);
52	      }
53	
54	      // Recover asset status if applicable (RETURN -> AVAILABLE, REPAIR -> IN_USE)
55	      const assetChanges: Record<string, unknown>[] = [];
56	      if (ticket.targetAsset) {
57	        const assetType = ticket.type as import("@prisma/client").TicketType;
58	        if (assetType === "RETURN" && ticket.targetAsset.status === "RETURNING") {
59	          const transition = await AssetStateMachine.transition(
60	            tx,
61	            ticket.targetAsset.id,
62	            "AVAILABLE",
63	            { operatorId: user.userId },
64	          );
65	          assetChanges.push(transition.after);
66	          await logAssetStatusChange(tx, {
67	            assetId: ticket.targetAsset.id,
68	            operatorId: user.userId,
69	            fromStatus: "RETURNING",
70	            toStatus: "AVAILABLE",
71	            metadata: { ticketId: id, reason: "rejected" },
72	          });
73	        } else if (assetType === "REPAIR" && ticket.targetAsset.status === "REPAIRING") {
74	          const transition = await AssetStateMachine.transition(
75	            tx,
76	            ticket.targetAsset.id,
77	            "IN_USE",
78	            { operatorId: user.userId },
79	          );
80	          assetChanges.push(transition.after);
81	          await logAssetStatusChange(tx, {
82	            assetId: ticket.targetAsset.id,
83	            operatorId: user.userId,
84	            fromStatus: "REPAIRING",
85	            toStatus: "IN_USE",
86	            metadata: { ticketId: id, reason: "rejected" },
87	          });
88	        }
89	      }
90	
91	      const updated = await tx.ticket.update({
92	        where: { id },
93	        data: {
94	          status: "REJECTED",
95	          rejectReason,
96	        },
97	      });
98	
99	      await logTicketStatusChange(tx, {
100	        ticketId: id,
101	        operatorId: user.userId,
102	        fromStatus: currentStatus,
103	        toStatus: "REJECTED",
104	        metadata: { rejectReason },
105	      });
106	
107	      await notifyApprovalResult(tx, {
108	        applicantId: ticket.applicantId,
109	        ticketId: id,
110	        approved: false,
111	        ticketType: ticket.type,
112	      });
113	
114	      return { ticket: updated, assetChanges };
115	    });
116	
117	    return Response.json(result);
118	  } catch (e) {
119	    if (e instanceof AuthError) {
120	      return Response.json({ error: e.message }, { status: e.statusCode });
121	    }
122	    if (e instanceof WorkflowError || e instanceof TransitionError) {
123	      return Response.json({ error: e.message }, { status: 400 });
124	    }
125	    return Response.json({ error: "Internal server error" }, { status: 500 });
126	  }
127	}
