14	
15	    if (!id || !sn || !modelId || !purchaseDate) {
16	      return Response.json(
17	        { error: "id, sn, modelId, and purchaseDate are required" },
18	        { status: 400 },
19	      );
20	    }
21	
22	    // Check unique constraints
23	    const existingId = await prisma.assetInstance.findUnique({ where: { id } });
24	    if (existingId) {
25	      return Response.json({ error: "Asset with this ID already exists" }, { status: 409 });
26	    }
27	
28	    const existingSn = await prisma.assetInstance.findUnique({ where: { sn } });
29	    if (existingSn) {
30	      return Response.json(
31	        { error: "Asset with this serial number already exists" },
32	        { status: 409 },
33	      );
34	    }
35	
36	    // Verify model exists
37	    const model = await prisma.assetModel.findUnique({ where: { id: modelId } });
38	    if (!model) {
39	      return Response.json({ error: "Asset model not found" }, { status: 404 });
40	    }
41	
42	    const result = await prisma.$transaction(async (tx) => {
43	      const asset = await tx.assetInstance.create({
44	        data: {
45	          id,
46	          sn,
47	          modelId,
48	          status: "IN_STOCK",
49	          deptId: deptId ?? null,
50	          purchaseDate: new Date(purchaseDate),
51	          warrantyExpiry: warrantyExpiry
52	            ? new Date(warrantyExpiry)
53	            : new Date(
54	                new Date(purchaseDate).getTime() +
55	                  model.warrantyMonths * 30 * 24 * 60 * 60 * 1000,
56	              ),
57	        },
58	      });
59	
60	      await logAssetStatusChange(tx, {
61	        assetId: asset.id,
62	        operatorId: user.userId,
63	        fromStatus: "NONE",
64	        toStatus: "IN_STOCK",
65	        metadata: { action: "inbound", sn, modelId },
66	      });
67	
68	      return asset;
69	    });
70	
71	    return Response.json(result, { status: 201 });
72	  } catch (e) {
73	    if (e instanceof AuthError) {
74	      return Response.json({ error: e.message }, { status: e.statusCode });
75	    }
76	    if (e instanceof TransitionError) {
77	      return Response.json({ error: e.message }, { status: 400 });
78	    }
79	    return Response.json({ error: "Internal server error" }, { status: 500 });
80	  }
81	}
