26	export async function apiFetch<T = unknown>(
27	  url: string,
28	  options: RequestInit = {},
29	): Promise<T> {
30	  const token = getToken();
31	
32	  const headers = new Headers(options.headers);
33	  headers.set("Content-Type", "application/json");
34	
35	  if (token) {
36	    headers.set("Authorization", `Bearer ${token}`);
37	  }
38	
39	  const response = await fetch(url, {
40	    ...options,
41	    headers,
42	  });
43	
44	  if (response.status === 401) {
45	    clearToken();
46	    throw new ApiError(401, "Unauthorized");
47	  }
48	
49	  if (!response.ok) {
50	    let message = `Request failed with status ${response.status}`;
51	    try {
52	      const body = await response.json();
53	      if (body.error) message = body.error;
54	      if (body.message) message = body.message;
55	    } catch {
56	      // ignore parse errors
57	    }
58	    throw new ApiError(response.status, message);
59	  }
60	
61	  // Handle 204 No Content
62	  if (response.status === 204) {
63	    return undefined as T;
64	  }
65	
66	  return response.json() as Promise<T>;
